import LocalAuthentication
import UIKit

class AuthenticationManager {
    static let shared = AuthenticationManager()
    private init() {}
    
    func authenticateUser(completion: @escaping (Bool, String?) -> Void) {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, "Biometric authentication not available")
            return
        }
        
        let reason = "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason, reply: { success, error in
            DispatchQueue.main.async {
                if success {
                    self.setAuthenticatedFlag()
                    completion(true, nil)
                } else {
                    let errorMessage = self.getErrorMessage(error)
                    completion(false, errorMessage)
                }
            }
        })
    }
    
    func setAuthenticatedFlag() {
        UserDefaults.standard.set(true, forKey: "isUserAuthenticated")
    }
    
    func isAuthenticated() -> Bool {
        return UserDefaults.standard.bool(forKey: "isUserAuthenticated")
    }
    
    func clearAuthenticationFlag() {
        UserDefaults.standard.set(false, forKey: "isUserAuthenticated")
    }
    
    private func getErrorMessage(_ error: Error?) -> String {
        guard let error = error else { return "Authentication failed" }
        
        switch error._code {
        case LAError.userCancel.rawValue:
            return "Authentication cancelled"
        case LAError.userFallback.rawValue:
            return "Fallback to password"
        case LAError.systemCancel.rawValue:
            return "System cancelled"
        case LAError.passcodeNotSet.rawValue:
            return "Passcode not set"
        case LAError.biometryNotAvailable.rawValue:
            return "Biometry not available"
        case LAError.biometryNotEnrolled.rawValue:
            return "Biometry not enrolled"
        case LAError.biometryLockout.rawValue:
            return "Biometry locked out"
        default:
            return "Authentication failed"
        }
    }
}

